external_knowledge:
- 'energy-hungry locations' refers to locations with the highest total energy consumption; 
- 'devoured the most power' refers to the highest total energy consumption;
- 'previous year' refers to the year 2023.

sql:
SELECT date_time, home_power
FROM energy_readings
WHERE home_power = (
    SELECT MAX(home_power)
    FROM energy_readings
);
